import React, { useContext, useState } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import {
  Drawer,
  AppBar,
  Toolbar,
  Typography,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Button,
  Box,
  Collapse,
} from '@mui/material';
import DashboardIcon from '@mui/icons-material/Dashboard';
import PointOfSaleIcon from '@mui/icons-material/PointOfSale';
import LogoutIcon from '@mui/icons-material/Logout';
import ExpandLess from '@mui/icons-material/ExpandLess';
import ExpandMore from '@mui/icons-material/ExpandMore';
import AssessmentIcon from '@mui/icons-material/Assessment';
import InventoryIcon from '@mui/icons-material/Inventory';
import { AuthContext } from '../context/AuthContext';

const drawerWidth = 240;

export default function AdminLayout() {
  const { logout, user } = useContext(AuthContext);
  const navigate = useNavigate();
  const location = useLocation();

  const [openHQ, setOpenHQ] = useState(true);
  const [openPOS, setOpenPOS] = useState(true);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  // Role checking helper
  const isSuperAdmin = user?.role?.name === 'SUPERADMIN';

  return (
    <Box sx={{ display: 'flex' }} className="bg-gray-50 min-h-screen">
      <AppBar
        position="fixed"
        sx={{ zIndex: (theme) => theme.zIndex.drawer + 1 }}
      >
        <Toolbar className="justify-between">
          <Typography variant="h6" noWrap component="div">
            Central POS System ({user?.role?.name})
          </Typography>
          <div className="flex items-center gap-4">
            <Typography variant="body2">Hello, {user?.name}</Typography>
            <Button
              color="inherit"
              onClick={handleLogout}
              startIcon={<LogoutIcon />}
            >
              Logout
            </Button>
          </div>
        </Toolbar>
      </AppBar>

      <Drawer
        variant="permanent"
        sx={{
          width: drawerWidth,
          flexShrink: 0,
          [`& .MuiDrawer-paper`]: {
            width: drawerWidth,
            boxSizing: 'border-box',
          },
        }}
      >
        <Toolbar />
        <Box sx={{ overflow: 'auto' }}>
          <List>
            {/* --- HQ Section (Only for SUPERADMIN) --- */}
            {isSuperAdmin && (
              <>
                <ListItem
                  button
                  onClick={() => {
                    setOpenHQ(!openHQ);
                    navigate('/hq-dashboard');
                  }}
                >
                  <ListItemIcon>
                    <DashboardIcon />
                  </ListItemIcon>
                  <ListItemText primary="HQ Dashboard" />
                  {openHQ ? <ExpandLess /> : <ExpandMore />}
                </ListItem>
                <Collapse in={openHQ} timeout="auto" unmountOnExit>
                  <List component="div" disablePadding>
                    <ListItem
                      button
                      sx={{ pl: 4 }}
                      onClick={() => navigate('/master-menu')}
                      selected={location.pathname === '/master-menu'}
                    >
                      <ListItemText primary="Master Menu" />
                    </ListItem>
                    <ListItem
                      button
                      sx={{ pl: 4 }}
                      onClick={() => navigate('/outlet-products')}
                      selected={location.pathname === '/outlet-products'}
                    >
                      <ListItemText primary="Outlet Products" />
                    </ListItem>
                  </List>
                </Collapse>
              </>
            )}

            {/* --- POS Section (Visible to Everyone) --- */}
            <ListItem button onClick={() => setOpenPOS(!openPOS)}>
              <ListItemIcon>
                <PointOfSaleIcon />
              </ListItemIcon>
              <ListItemText primary="POS Terminal" />
              {openPOS ? <ExpandLess /> : <ExpandMore />}
            </ListItem>
            <Collapse in={openPOS} timeout="auto" unmountOnExit>
              <List component="div" disablePadding>
                <ListItem
                  button
                  sx={{ pl: 4 }}
                  onClick={() => navigate('/pos')}
                  selected={location.pathname === '/pos'}
                >
                  <ListItemText primary="All Products" />
                </ListItem>
                <ListItem
                  button
                  sx={{ pl: 4 }}
                  onClick={() => navigate('/sales-report')}
                  selected={location.pathname === '/sales-report'}
                >
                  <ListItemText primary="Sales Report" />
                </ListItem>
              </List>
            </Collapse>
          </List>
        </Box>
      </Drawer>

      <Box component="main" sx={{ flexGrow: 1, p: 3 }}>
        <Toolbar />
        <Outlet />
      </Box>
    </Box>
  );
}
